package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.util.ArrayList;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class NonNullElementWrapperListTest {

  NonNullElementWrapperList<String> list;
  ArrayList<String> delegateMock;

  @BeforeEach
  void setUp() throws Exception {
    delegateMock = mock(ArrayList.class, withSettings().defaultAnswer(CALLS_REAL_METHODS).name("delegateMock").lenient());
    list = new NonNullElementWrapperList<>(delegateMock);
  }

  @Test
  void equals_sameDelegateObject_returnsTrue() {
    Object other = new Object();
    // Cannot mock equals directly on delegateMock because equals is final
    // Instead, call equals on the delegateMock's real equals method by spying or use spy
    // So use spy instead of mock for delegateMock to override equals method behavior.
    // But since delegateMock is a mock, we cannot stub equals.
    // Instead, test list.equals(delegateMock) and list.equals(other) directly.

    // We test list.equals(other) returns what delegateMock.equals(other) returns.
    // So we create a spy on delegateMock to stub equals.
    ArrayList<String> spyDelegate = spy(new ArrayList<>());
    list = new NonNullElementWrapperList<>(spyDelegate);

    doReturn(true).when(spyDelegate).equals(other);

    boolean result = list.equals(other);

    assertTrue(result);
    verify(spyDelegate).equals(other);
  }

  @Test
  void equals_differentDelegateObject_returnsFalse() {
    Object other = new Object();
    ArrayList<String> spyDelegate = spy(new ArrayList<>());
    list = new NonNullElementWrapperList<>(spyDelegate);

    doReturn(false).when(spyDelegate).equals(other);

    boolean result = list.equals(other);

    assertFalse(result);
    verify(spyDelegate).equals(other);
  }

  @Test
  void equals_nullObject_returnsFalse() {
    ArrayList<String> spyDelegate = spy(new ArrayList<>());
    list = new NonNullElementWrapperList<>(spyDelegate);

    doReturn(false).when(spyDelegate).equals(null);

    boolean result = list.equals(null);

    assertFalse(result);
    verify(spyDelegate).equals(null);
  }

  @Test
  void equals_selfObject_returnsTrue() {
    ArrayList<String> spyDelegate = spy(new ArrayList<>());
    list = new NonNullElementWrapperList<>(spyDelegate);

    doReturn(true).when(spyDelegate).equals(list);

    boolean result = list.equals(list);

    assertTrue(result);
    verify(spyDelegate).equals(list);
  }

  @Test
  void equals_delegateEqualsThrowsException_propagates() {
    Object other = new Object();
    ArrayList<String> spyDelegate = spy(new ArrayList<>());
    list = new NonNullElementWrapperList<>(spyDelegate);

    doThrow(new RuntimeException("fail")).when(spyDelegate).equals(other);

    RuntimeException thrown = assertThrows(RuntimeException.class, () -> list.equals(other));
    assertEquals("fail", thrown.getMessage());
  }
}
